import React, { Component } from 'react';
import PropTypes from 'prop-types';
import {connect} from 'react-redux';
import {withStyles} from '@material-ui/core/styles';
import { 
    headerActions, headerStrings, breadCrumbActions, 
    mainStageHeaderAction, mainStageHeaderStrings, 
    SimpleListBoard, MyListCard 
} from "../../utils";
import { routeNamesInventory } from '../../routeNames';
import { invSupplierActions } from '../actions';
import { Grid, Typography } from '@material-ui/core';
import { ItemDisplayCard } from '../../INVProducts';
import { invSupplierStrings } from '../config';
import { inventoryUtil } from '../../utils';

const style = theme => ({
    root: {
        marginTop : 20
    },
    name : {
        fontWeight : "bold",
        color : inventoryUtil.getTheme().secondary
    }
})
class _Supplier extends Component {
    constructor(props) {
        super(props);
        this.state = {
            supplier : null
        }
        const {dispatch} = props;
        this.supplierId = this.props.match.params.id;
        headerActions({
            [headerStrings.headerTitle] : "SUPPLIER",
            [headerStrings.backButtonAction] : ()=>{}
        })(dispatch);
        breadCrumbActions.addToBreadCrumb([
            {name : "Supplier", path : routeNamesInventory.supplier_+this.supplyId}
        ])(dispatch);
        mainStageHeaderAction({})(dispatch);
    }
    componentDidMount(){
        const{
            dispatch,
            [invSupplierStrings.stockCategories] : stockCategories,
            [invSupplierStrings.itemPackages] : itemPackages,
            [invSupplierStrings.itemTags] : itemTags,
        }=this.props;
        invSupplierActions.getSupplier_NO_DISPATCH(this.supplierId, (done, result, message)=>{
            if(done) this.setState({supplier : result});
        });
        if(!stockCategories) invSupplierActions.getStockCategories()(dispatch);
        if(!itemPackages) invSupplierActions.getItemPackages()(dispatch);
        if(!itemTags) invSupplierActions.getItemTags()(dispatch);
    }
    render() {
        const {
            classes,
            [invSupplierStrings.stockCategories] : stockCategories,
            [invSupplierStrings.itemPackages] : itemPackages,
            [invSupplierStrings.itemTags] : itemTags
        } = this.props;
        const { name, contactInfo, brands, items} = this.state.supplier || {};
        return (
            <Grid container spacing={2} className={classes.root}>
                {name && <Grid item xs={12} sm={12} md={12} lg={12} xl={12}>
                        <Typography variant="h4" className={classes.name}>{name}</Typography>
                </Grid>}
                {contactInfo && <Grid item xs={12} sm={6} md={6} lg={6} xl={6}>
                    <SimpleListBoard 
                    title="Contact Information"
                    data={contactInfo}
                    skip={[]}
                    nameMapper={name=>name}/>
                </Grid>}
                {brands && <Grid item xs={12} sm={6} md={6} lg={6} xl={6}>
                    <MyListCard
                        title="Brands"
                        list={brands}
                        itemNameProp="name"
                        />
                </Grid>}
                {items && items.map(
                    (item, index)=><Grid
                            key={index} item xs={12} sm={6} md={6} lg={4} xl={4}>
                        <ItemDisplayCard
                            item={item}
                            brands={brands}
                            stockCategories={stockCategories}
                            itemPackages={itemPackages}
                            itemTags={itemTags}
                        />
                    </Grid>
                )}
            </Grid>
        );
    }
}


_Supplier.propTypes = {
    classes : PropTypes.object.isRequired
};
const mapStateToProps = ({invSupplierReducer}) => ({
    [invSupplierStrings.stockCategories] : invSupplierReducer[invSupplierStrings.stockCategories],
    [invSupplierStrings.itemPackages] : invSupplierReducer[invSupplierStrings.itemPackages],
    [invSupplierStrings.itemTags] : invSupplierReducer[invSupplierStrings.itemTags],
})


export const Supplier = connect(mapStateToProps)(withStyles(style)(_Supplier));
export {Supplier as default}